$path = Get-Item "D:\inspe*\sw.js" | Select-Object -First 1 -ExpandProperty FullName
Write-Host "Found: $path"

$fcmCode = "`r`n// === FCM Background Handler ===`r`ntry {`r`n    importScripts('https://www.gstatic.com/firebasejs/9.23.0/firebase-app-compat.js');`r`n    importScripts('https://www.gstatic.com/firebasejs/9.23.0/firebase-messaging-compat.js');`r`n`r`n    firebase.initializeApp({`r`n        apiKey: 'AIzaSyDPNVb9FK5rlUtYt0OVb6PXU-APYmp99aw',`r`n        authDomain: 'inspecaopro-1989.firebaseapp.com',`r`n        projectId: 'inspecaopro-1989',`r`n        storageBucket: 'inspecaopro-1989.firebasestorage.app',`r`n        messagingSenderId: '826135664752',`r`n        appId: '1:826135664752:web:e530bb43feac9c29b23cb5'`r`n    });`r`n`r`n    var fcmMessaging = firebase.messaging();`r`n`r`n    fcmMessaging.onBackgroundMessage(function(payload) {`r`n        console.log('[FCM-SW] Background message:', payload);`r`n        var n = payload.notification || {};`r`n        var d = payload.data || {};`r`n        var title = n.title || d.title || 'Inspecao Pro';`r`n        var body = n.body || d.body || '';`r`n        return self.registration.showNotification(title, {`r`n            body: body,`r`n            icon: './icon.png',`r`n            badge: './icon-192.png',`r`n            tag: 'fcm-chat-' + Date.now(),`r`n            renotify: true,`r`n            data: d`r`n        });`r`n    });`r`n    console.log('[FCM-SW] Firebase Messaging integrado ao SW principal');`r`n} catch(e) {`r`n    console.warn('[FCM-SW] Erro ao inicializar FCM no SW:', e);`r`n}`r`n"

Add-Content -LiteralPath $path -Value $fcmCode -Encoding UTF8
Write-Host "Done appending FCM code to sw.js"
